import{_ as e,o as t,c as a,ai as i}from"./chunks/framework.EKiYdDTS.js";const k=JSON.parse('{"title":"Tools","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/tools.md","filePath":"concepts/tools.md","rawMarkdown":"# Tools\\n\\nTools are functions that the model can call during the [agent loop](/concepts/agent-loop). When the model decides it needs to read a file, run a command, or fetch a URL, it emits a tool call ‚Äî ra executes it and feeds the result back.\\n\\nThe model doesn\'t execute tools directly. It describes _what_ it wants to do, and ra handles the _how_.\\n\\n## Built-in tools\\n\\nra ships with tools for the most common agent tasks:\\n\\n| Category | Tools |\\n|----------|-------|\\n| **Filesystem** | `Read`, `Write`, `Edit`, `Glob`, `Grep`, `LS`, `MoveFile`, `CopyFile`, `DeleteFile`, `AppendFile` |\\n| **Shell** | `Bash` (Linux/Mac), `PowerShell` (Windows) |\\n| **Network** | `WebFetch` |\\n| **Agent** | `Agent` (spawn sub-agents for parallel work) |\\n\\nThese cover file manipulation, code search, shell commands, and HTTP requests ‚Äî enough for most coding and automation tasks.\\n\\n## Custom tools\\n\\nYou can define your own tools as TypeScript files or shell scripts and register them via config. Custom tools go through the same execution pipeline as built-in tools ‚Äî with full logging, tracing, permissions, and middleware support.\\n\\n```yaml\\nagent:\\n  tools:\\n    custom:\\n      - \\"./tools/deploy.ts\\"          # TypeScript\\n      - \\"./tools/health-check.sh\\"    # Shell script (auto-detected)\\n```\\n\\nShell scripts self-describe via a `--describe` flag and receive input as JSON on stdin ‚Äî the same execution engine used by [shell middleware](/middleware/#shell-middleware).\\n\\nSee [Custom Tools](/tools/custom) for the full guide.\\n\\n## MCP tools\\n\\nBeyond built-in and custom tools, ra can connect to external [MCP servers](/modes/mcp) to pull in additional tools. This means you can give your agent access to databases, APIs, Slack, GitHub, or anything else that exposes an MCP interface.\\n\\n```yaml\\napp:\\n  mcpServers:\\n    - name: github\\n      transport: stdio\\n      command: npx @modelcontextprotocol/server-github\\n```\\n\\nMCP tools are prefixed with the server name (e.g., `github__create_issue`) to avoid conflicts with built-in tools.\\n\\n## How tools work\\n\\nEach tool defines:\\n\\n- **name** ‚Äî what the model calls it (e.g., `Read`)\\n- **description** ‚Äî tells the model when and how to use it\\n- **inputSchema** ‚Äî JSON Schema for the tool\'s parameters\\n- **execute()** ‚Äî the function that runs when the tool is called\\n\\nWhen the model emits a tool call, ra:\\n\\n1. Looks up the tool in the registry\\n2. Checks [permissions](/permissions/) (if configured)\\n3. Fires `beforeToolExecution` middleware\\n4. Calls `execute()` with the parsed arguments\\n5. Fires `afterToolExecution` middleware\\n6. Sends the result back to the model\\n\\n## Permissions\\n\\nYou can restrict what tools are allowed to do using regex-based rules:\\n\\n```yaml\\nagent:\\n  permissions:\\n    rules:\\n      - tool: Bash\\n        command:\\n          allow: [\\"^git \\", \\"^bun \\"]\\n          deny: [\\"rm -rf\\", \\"--force\\"]\\n```\\n\\nWhen a tool call is denied, the model receives a clear error message and can adjust its approach. See [Permissions](/permissions/) for the full rule format.\\n\\n## Timeouts\\n\\nEach tool call has a timeout (default: 120 seconds). Long-running commands won\'t hang the loop forever:\\n\\n```yaml\\nagent:\\n  toolTimeout: 120000  # ms\\n```\\n\\nSee [Built-in Tools](/tools/) for details on each tool.\\n"}'),o={name:"concepts/tools.md"};function n(l,s,h,r,d,p){return t(),a("div",null,[...s[0]||(s[0]=[i("",29)])])}const u=e(o,[["render",n]]);export{k as __pageData,u as default};
